#include <cuda_runtime.h>
#include <cuda_fp16.h>
#include <vector>

#define BLOCK_SIZE 256

template<typename scalar_t>
__global__ void conv_transpose2d_kernel(
    const scalar_t* input,
    const scalar_t* weight,
    scalar_t* output,
    const int batch_size,
    const int in_channels,
    const int out_channels,
    const int input_height,
    const int input_width,
    const int output_height,
    const int output_width,
    const int kernel_h,
    const int kernel_w,
    const int stride_h,
    const int stride_w,
    const int padding_h,
    const int padding_w,
    const int dilation_h,
    const int dilation_w,
    const int groups,
    const scalar_t* bias) {

    // Each thread handles one output pixel for one output channel
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx >= batch_size * out_channels * output_height * output_width) return;

    int n = idx / (out_channels * output_height * output_width);
    int oc = (idx / (output_height * output_width)) % out_channels;
    int oh = (idx / output_width) % output_height;
    int ow = idx % output_width;

    scalar_t result = scalar_t(0);

    // Calculate group information
    int group_size = out_channels / groups;
    int group_idx = oc / group_size;
    int in_channels_per_group = in_channels / groups;

    // Loop over input channels in this group
    for (int ic = 0; ic < in_channels_per_group; ic++) {
        int input_channel = group_idx * in_channels_per_group + ic;

        // Loop over kernel
        for (int kh = 0; kh < kernel_h; kh++) {
            for (int kw = 0; kw < kernel_w; kw++) {
                // Calculate input position for this kernel element
                int ih = oh - kh * dilation_h + padding_h;
                int iw = ow - kw * dilation_w + padding_w;

                // Check if input position is valid and divisible by stride
                if (ih >= 0 && iw >= 0 && 
                    ih % stride_h == 0 && iw % stride_w == 0) {

                    ih = ih / stride_h;
                    iw = iw / stride_w;

                    if (ih < input_height && iw < input_width) {
                        // Weight index calculation for ConvTranspose2d
                        // Weight shape: [in_channels, out_channels/groups, kH, kW]
                        int weight_idx = ((input_channel * (out_channels/groups) + (oc % group_size)) / kernel_h + kh) * kernel_w + kw;

                        // Input index calculation
                        int input_idx = ((n * in_channels + input_channel) * input_height + ih) * input_width + iw;

                        result += input[input_idx] * weight[weight_idx];
                    }
                }
            }
        }
    }

    // Add bias if present
    if (bias != nullptr) {
        result += bias[oc];
    }

    int output_idx = ((n * out_channels + oc) * output_height + oh) * output_width + ow;
    output[output_idx] = result;
}

