    """
    Optimized ConvTranspose2d with custom CUDA kernel.
    Features:
    1. Correct ConvTranspose2d algorithm implementation
    2. Optimized memory access patterns
    3. Support for mixed precision (FP16/FP32)
    4. Proper handling of groups parameter
    """
    def __init__(self, in_channels: int, out_channels: int, kernel_size: tuple, 
                 stride: tuple = (1, 1), padding: tuple = (0, 0), 
                 output_padding: tuple = (0, 0), dilation: tuple = (1, 1), 
                 groups: int = 1, bias: bool = False):
        super(ModelNew, self).__init__()

        self.in_channels = in_channels
        self.out_channels = out_channels
        self.kernel_size = kernel_size
        self.stride = stride
        self.padding = padding
        self.output_padding = output_padding
        self.dilation = dilation
        self.groups = groups

        # Validate parameters
        assert in_channels % groups == 0, "in_channels must be divisible by groups"
        assert out_channels % groups == 0, "out_channels must be divisible by groups"

        # Initialize weight tensor with correct shape for ConvTranspose2d
        # Weight shape: [in_channels, out_channels // groups, kernel_h, kernel_w]
        self.weight = nn.Parameter(torch.empty(
            in_channels, 
            out_channels // groups, 
            kernel_size[0], 
            kernel_size[1]
        ))

        # Initialize bias if needed
        if bias:
            self.bias = nn.Parameter(torch.empty(out_channels))
        else:
            self.register_parameter('bias', None)

        # Initialize parameters
        self.reset_parameters()

        # Load custom CUDA operator
        self.conv_transpose2d_op = conv_transpose2d_op

    def reset_parameters(self):
        nn.init.kaiming_uniform_(self.weight, a=5**0.5)
        if self.bias is not None:
            fan_in, _ = nn.init._calculate_fan_in_and_fan_out(self.weight)
            bound = 1 / (fan_in ** 0.5)
            nn.init.uniform_(self.bias, -bound, bound)

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        # Create empty tensor for bias if not used
        bias_tensor = self.bias if self.bias is not None else torch.tensor([], device=x.device, dtype=x.dtype)

        return self.conv_transpose2d_op.optimized_conv_transpose2d_cuda(
            x,
            self.weight,
            bias_tensor,
            self.stride[0],
            self.stride[1],
            self.padding[0],
            self.padding[1],
            self.output_padding[0],
            self.output_padding[1],
            self.dilation[0],
            self.dilation[1],
            self.groups
        )

